SourceCode.Declaration:
[BusinessEvents(classStr(ETGDMSSalesAgreementConfirmationContract),
"ETG sales agreement confirmation ",
    "This business event will trigger when sales agreement confirmation.",
    ModuleAxapta::AccountsPayable)]
 class ETGDMSSalesAgreementConfirmationEventClass extends BusinessEventsBase
{

    private SalesAgreementHeader            salesAgreementHeader;
    private AgreementHeader                 agreementHeader;

}

Method.Source:
public static ETGDMSSalesAgreementConfirmationEventClass newFromsalesAgreement(SalesAgreementHeader  _salesAgreementHeader, AgreementHeader _agreementHeader)
{
    ETGDMSSalesAgreementConfirmationEventClass businessEvent = new ETGDMSSalesAgreementConfirmationEventClass();
    businessEvent.parmsalesAgreementHeader(_salesAgreementHeader);
    businessEvent.parmagreementHeader(_agreementHeader);
    businessEvent.buildContract();
    return businessEvent;
}

private SalesAgreementHeader parmsalesAgreementHeader(SalesAgreementHeader _salesAgreementHeader = salesAgreementHeader)
{
    salesAgreementHeader = _salesAgreementHeader;
    return salesAgreementHeader;
}

private AgreementHeader parmagreementHeader(AgreementHeader _agreementHeader = agreementHeader)
{
    agreementHeader = _agreementHeader;
    return agreementHeader;
}

[Wrappable(true), Replaceable(true)]
public BusinessEventsContract buildContract()
{
    return ETGDMSSalesAgreementConfirmationContract::newFromsalesAgreement(salesAgreementHeader, agreementHeader);
}
